// Build date range for last 7 days
const now = new Date();
const weekStart = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString();
const weekEnd = now.toISOString();

const dateStr = `Week ending ${now.toLocaleDateString('en-US', {
  year: 'numeric', month: 'long', day: 'numeric',
  timeZone: 'America/Chicago'
})}`;

return [{ json: { weekStart, weekEnd, dateStr } }];

// Filter to last 7 days and build compact batch input
const items = $input.all();
const weekStart = $('Build Week Date Range').first().json.weekStart;
const weekEnd = $('Build Week Date Range').first().json.weekEnd;

const weekSignals = items.filter(item => {
  const capturedAt = item.json.captured_at || '';
  return capturedAt >= weekStart && capturedAt <= weekEnd;
});

// Build compact signal list (title, lane, cluster, score)
const lines = weekSignals.map((item, i) => {
  const s = item.json;
  return `[${i+1}] LANE: ${s.lane} | SCORE: ${s.score} | TYPE: ${s.signal_type} | CLUSTER: ${s.keyword_cluster}\nTITLE: ${s.title}\n`;
});

return [{
  json: {
    weekly_signals_input: lines.join('\n'),
    signal_count: weekSignals.length,
    dateStr: $('Build Week Date Range').first().json.dateStr,
  }
}];

const reportData = $input.first().json;
const dateStr = $('Filter + Format Week Signals').first().json.dateStr;
const signalCount = $('Filter + Format Week Signals').first().json.signal_count;

const reportText = reportData.content?.[0]?.text || reportData.text || 'Weekly report generation failed.';

const htmlBody = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: Georgia, serif; max-width: 700px; margin: 0 auto; padding: 24px; color: #1a1a1a; }
    h1 { font-size: 22px; border-bottom: 2px solid #333; padding-bottom: 8px; }
    h2 { font-size: 16px; color: #444; margin-top: 28px; }
    .meta { font-size: 13px; color: #888; margin-bottom: 24px; }
    .footer { font-size: 12px; color: #aaa; border-top: 1px solid #eee; padding-top: 12px; margin-top: 32px; }
  </style>
</head>
<body>
  <h1>BizDeedz Signal Engine — Weekly Report</h1>
  <p class="meta">${dateStr} &nbsp;|&nbsp; Signals analyzed: ${signalCount}</p>
  <div>${reportText.replace(/\n/g, '<br>').replace(/## (.+)/g, '<h2>$1</h2>').replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')}</div>
  <div class="footer">BizDeedz Signal Engine Weekly Report</div>
</body>
</html>`;

return [{ json: {
  subject: `BizDeedz Weekly Intelligence Report — ${dateStr}`,
  htmlBody,
  plainText: reportText,
} }];
